import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - nextGeneration", () => {
  // Simplest case: single cell dies (rule 1, underpopulation with 0 neighbors)
  it.todo("single live cell at (0,0) dies with 0 neighbors -- next gen is []");

  // Rule 1: Underpopulation - two adjacent cells each have 1 neighbor and die
  it.todo("two adjacent live cells [(0,1),(1,1)] each have 1 neighbor and die -- next gen is []");

  // Rule 3: Overpopulation - center cell with 4 neighbors dies (from the rule 3 example)
  it.todo("center cell (1,1) with 4 live neighbors dies (rule 3 overpopulation example)");

  // Rule 4: Reproduction - dead cell with exactly 3 neighbors becomes alive
  it.todo("dead cell (1,1) with exactly 3 live neighbors becomes alive -- gen0 [(0,0),(1,0),(0,1)] -> gen1 [(0,0),(1,0),(0,1),(1,1)]");

  // Rule 2: Survival - center cell with 3 neighbors survives (from rule 2 example)
  it.todo("rule 2 survival example: gen0 [(0,0),(1,0),(2,0),(1,2)] -> gen1 [(1,0),(1,1)] (center (1,1) becomes alive, (1,0) survives with 2 neighbors)");

  // Pattern: Block (still life) - 2x2 block stays the same
  it.todo("block still life [(0,0),(1,0),(0,1),(1,1)] remains unchanged");

  // Pattern: Single cell dies
  it.todo("single cell [(0,0)] dies -- next gen is []");

  // Pattern: Blinker (oscillator) - vertical to horizontal
  it.todo("blinker gen0 [(0,0),(0,1),(0,2)] -> gen1 [(-1,1),(0,1),(1,1)] (vertical to horizontal)");

  // Pattern: Blinker oscillates back
  it.todo("blinker gen1 [(-1,1),(0,1),(1,1)] -> gen2 [(0,0),(0,1),(0,2)] (horizontal back to vertical)");

  // Negative coordinates work
  it.todo("handles negative coordinates: block at [(-1,-1),(0,-1),(-1,0),(0,0)] remains unchanged");
});

